$_MODULE['<{mondialrelay}prestashop>content_1e25f375279ba33cb0da5862bd3a356a'] = '[1] Om u te begeleiden, trekken we alles uit de kast!  Mondial Relay - InPost, de leider in out-of-home delivery in Europa [/1]';
$_MODULE['<{mondialrelay}prestashop>content_30b8a21d08ef40faf8e80282b5b18fe4'] = 'Mondial Relay - InPost, iedereen weet het,  is al meer dan 25 jaar de specialist in pakketbezorging aan particulieren via zijn distributieoplossingen in onze Afhaalpunt® en Automatisch Afhaalpunt® zoeken en at Home in Europa.';
$_MODULE['<{mondialrelay}prestashop>content_023bb091065af2a91af12121dc4dee1f'] = 'Maar het zijn ook meer dan 9 Europese distributielanden, meer dan 150 000 e-merchants die ons hun pakketten toevertrouwen, meer dan 45 000 afhaalpunten in Europa, meer innovaties om het leven van iedereen te vereenvoudigen en meer gemak en veiligheid voor klanten tegen de beste prijs.';
$_MODULE['<{mondialrelay}prestashop>content_1ddafceab03be7e828ce610048d8e149'] = ' Bied uw klanten een eenvoudige, veilige en praktische economische leveringsdienst:';
$_MODULE['<{mondialrelay}prestashop>content_5663efd5d0ae25b5d1643b23c385da5e'] = '[1] Voordelig [/1] : Geen dure pakketleveringen meer! Met Mondial Relay - InPost geniet de consument van een onklopbare prijs-kwaliteitverhouding.';
$_MODULE['<{mondialrelay}prestashop>content_140f0f35ff86c9af93245d6b08b9ea26'] = '[1] Eenvoudig [/1] : wij hebben slechts één idee voor ogen \"het leven van iedereen vereenvoudigen\". Een pakje versturen of ontvangen met Mondial Relay - InPost is zo eenvoudig als een glimlach.';
$_MODULE['<{mondialrelay}prestashop>content_2d2c3abb1283d8a4b38868ee98eefe5a'] = '[1] Veilig en praktisch [/1] : Mondial Relay - InPost zorgt voor uw zendingen. Met rigoureuze tracking kunnen klanten hun pakket volgen en afhalen bij een van onze Afhaalpunt® en Automatisch Afhaalpunt® zoeken met behulp van een PIN- of QR-code.';
$_MODULE['<{mondialrelay}prestashop>content_b1ed83ef2fcfcfff29a73e07aaeecde0'] = 'Mondial Relay wordt dagelijks door honderden klanten geëvalueerd dankzij de organisatie Avis Vérifiés, gecertificeerd door AFNOR, die een score van 9,1/10 geeft.';
$_MODULE['<{mondialrelay}prestashop>content_b081f23af33c6e7502acab8b71a9aea5'] = 'Ontdek de aanbiedingen van Mondial Relay - InPost';
$_MODULE['<{mondialrelay}prestashop>content_d943ddad1a8060a8dd51f3c12713e6a0'] = 'Bied uw klanten een betaalbaar, eenvoudig, veilig en gemakkelijk leveringsaanbod.';
$_MODULE['<{mondialrelay}prestashop>content_9f35639eb56fc42b6a5731a474d810bc'] = 'Het aanbod van Mondial Relay';
$_MODULE['<{mondialrelay}prestashop>display_mode_description_82af2c60811a72571e4ea942d0d55410'] = 'Kies een manier om de Afhaalpunt® voor uw winkel weer te geven.';
$_MODULE['<{mondialrelay}prestashop>display_mode_description_b35ac93e97894f42d54ff9c82a9cd81e'] = 'Normale modus: responsief zonder kaart';
$_MODULE['<{mondialrelay}prestashop>display_mode_description_846b8507e2f43c525989d678fc07026f'] = 'Widgetmodus: responsief met een kaart';
$_MODULE['<{mondialrelay}prestashop>content_50210436fc7e78da4182f21963b3a136'] = 'Al meer dan 20 jaar is Mondial Relay de specialist in pakketvervoer met het grootste Europese e-commerceleveringsnetwerk. Het bedrijf is een van de grootste vervoerders van e-commercepakketten in Frankrijk en Europa voor meer dan 40.000 e-handelaars, met pakketleveringsoplossingen in Frankrijk en Europa, zoals Afhaalpunten, Drive (ophalen met de wagen) en Home (thuisbezorging).';
$_MODULE['<{mondialrelay}prestashop>content_ff390019e65d83b32ddc50435476c2fe'] = 'Bied uw klanten een betaalbaar, eenvoudig, veilig en gemakkelijk leveringsaanbod:';
$_MODULE['<{mondialrelay}prestashop>content_4a3366d5a627724bf9a32f4b6d6ed0ee'] = '[1] Betaalbaar [/1]: Lage tarieven vanaf  3,79 (ex btw)!';
$_MODULE['<{mondialrelay}prestashop>content_2016814d95f7ccb9d1d5de518a8d0a53'] = '[1] Gemakkelijk [/1]: Het verzenden of ontvangen van een pakket is nog nooit zo eenvoudig geweest met alle oplossingen die Mondial Relay biedt. Afhaalpunt® (afhaalpunt) wordt steeds populairder!';
$_MODULE['<{mondialrelay}prestashop>content_dadf83db013c1824f0a44d269c5f83d7'] = '[1] Veilig en praktisch [/1]: Mondial Relay draagt zorg voor uw pakketten. Via het betrouwbare volgsysteem kunnen de klanten hun pakket volgen en ophalen bij een van onze Afhaalpunten of thuis laten bezorgen (uitgezonderd Frankrijk).';
$_MODULE['<{mondialrelay}prestashop>content_17ee3ace47ac0bfecdf46ce2c0ee56e5'] = 'Mondial Relay wordt dagelijks door honderden klanten beoordeeld en heeft een score van 4,4/5.';
$_MODULE['<{mondialrelay}prestashop>list_header_5ae4c97a0358acbea4034a55a1c02be1'] = 'U moet een Cron-taak aanmaken op uw server voor het bijwerken van de bestelstatus als de bestelling verzonden is.';
$_MODULE['<{mondialrelay}prestashop>list_header_690361676eb5b079dc16d187d759035b'] = 'De CRON-taak wordt gebruikt voor het instellen van de frequentie van de oproepen aan onze volgservice om de pakketten met de status \"Afgeleverd\" te zien. Wij adviseren om een oproepfrequentie van 6 uur in te stellen.';
$_MODULE['<{mondialrelay}prestashop>form_1f1b444db5dd8820aa92f68a4def749e'] = 'Deze bestelling gebruikt een Mondial Relay-vervoerder, maar er is geen Afhaalpunt® geselecteerd.';
